const kpis = $('Get KPI Snapshots').all();
const channels = $('Get Channel Performance').all();
const campaigns = $('Get Top Campaigns').all();
const client = $('Get Active Clients').first().json;

const latest = kpis[0]?.json || {};
const targetDate = $now.minus({ days: 7 }).toFormat('yyyy-MM-dd');
const previous = (kpis.find(k => k.json.snapshot_date <= targetDate) || kpis[kpis.length - 1])?.json || {};

const periodStart = $now.minus({ days: 7 }).toFormat('yyyy-MM-dd');
const periodEnd = $now.minus({ days: 1 }).toFormat('yyyy-MM-dd');

const channelLines = channels.map(c =>
  `- ${c.json.channel}: $${(c.json.total_revenue || 0).toFixed(2)} revenue, $${(c.json.total_spend || 0).toFixed(2)} spend, ${(c.json.roas || 0).toFixed(2)}x ROAS`
).join('\n') || '- No channel data available';

const campaignLines = campaigns.slice(0, 5).map(c =>
  `- ${c.json.campaign_name} (${c.json.platform}): $${(c.json.revenue || 0).toFixed(2)} rev, ${(c.json.roas || 0).toFixed(2)}x ROAS, ${c.json.status}`
).join('\n') || '- No campaign data available';

const revChange = previous.total_revenue > 0
  ? (((latest.total_revenue - previous.total_revenue) / previous.total_revenue) * 100).toFixed(1)
  : 'N/A';

const prompt = `You are a marketing analytics expert generating a weekly performance report for ${client.company_name || 'our client'} (${client.niche || 'ecommerce'} industry).

## This Week's KPIs (${periodStart} to ${periodEnd})
- Total Revenue: $${(latest.total_revenue || 0).toFixed(2)} (vs last week: $${(previous.total_revenue || 0).toFixed(2)}, change: ${revChange}%)
- Ad Spend: $${(latest.ad_spend || 0).toFixed(2)} (vs last week: $${(previous.ad_spend || 0).toFixed(2)})
- ROAS: ${(latest.roas || 0).toFixed(2)}x (vs last week: ${(previous.roas || 0).toFixed(2)}x)
- Conversion Rate: ${(latest.conversion_rate || 0).toFixed(2)}% (vs last week: ${(previous.conversion_rate || 0).toFixed(2)}%)
- Total Orders: ${latest.total_orders || 0}
- Total Sessions: ${latest.total_sessions || 0}
- Avg Order Value: $${(latest.avg_order_value || 0).toFixed(2)}

## Channel Breakdown
${channelLines}

## Top Campaigns
${campaignLines}

## Instructions
Write a concise, insightful weekly report in HTML format. Use <p> tags for paragraphs. Highlight key numbers with <span class="hl"> tags. Use <strong> for emphasis.

Then provide exactly 3 insights labeled clearly:
1. Win — the best performing thing this week
2. Watch — something that needs attention
3. Next — a recommended action

Format each insight as:
[number]. [Win/Watch/Next]: [Title]
[Body text of the insight]

Keep the tone professional but conversational. Total length: 3 short paragraphs + 3 insights.`;

return [{ json: { prompt, client_id: client.client_id, period_start: periodStart, period_end: periodEnd } }];

const response = $input.first().json;
const promptData = $('Build Prompt').first().json;
const clientItem = $('Get Active Clients').first().json;
const content = response.choices?.[0]?.message?.content || '';

// Split body from insights
const parts = content.split(/(?=\d+\.\s*(?:Win|Watch|Next))/i);
const bodyHtml = parts[0].trim();

const insights = [];
for (let i = 1; i < parts.length && i <= 3; i++) {
  const text = parts[i].trim();
  const typeMatch = text.match(/\d+\.\s*(Win|Watch|Next)/i);
  const type = typeMatch ? typeMatch[1].toLowerCase() : ['win', 'watch', 'next'][i - 1];

  // Extract title after the type label (e.g., "1. Win: Title here")
  const titleMatch = text.match(/\d+\.\s*(?:Win|Watch|Next)[:\s]+([^\n]+)/i);
  const title = titleMatch ? titleMatch[1].trim() : type.charAt(0).toUpperCase() + type.slice(1);

  // Rest is the body
  const lines = text.split('\n').filter(l => l.trim());
  const body = lines.slice(1).join(' ').trim();

  insights.push({ type, title, text: body });
}

// Pad insights to always have 3
const defaultInsights = [
  { type: 'win', title: 'Top Performer', text: 'Review your best performing campaign this week.' },
  { type: 'watch', title: 'Area to Monitor', text: 'Keep an eye on your conversion rate trends.' },
  { type: 'next', title: 'Recommended Action', text: 'Consider optimizing your top ad spend channel.' }
];
for (let i = insights.length; i < 3; i++) {
  insights.push(defaultInsights[i]);
}

return [{
  json: {
    client: clientItem.client_id,
    body_html: bodyHtml,
    insight_1_type: insights[0].type,
    insight_1_title: insights[0].title,
    insight_1_text: insights[0].text,
    insight_2_type: insights[1].type,
    insight_2_title: insights[1].title,
    insight_2_text: insights[1].text,
    insight_3_type: insights[2].type,
    insight_3_title: insights[2].title,
    insight_3_text: insights[2].text,
    period_start: promptData.period_start,
    period_end: promptData.period_end,
    generated_at: new Date().toISOString(),
    status: 'Draft'
  }
}];
